// LESSON: Reference Page 1 - String och text.
// You will learn: Compare, transform, and build text without mutating String.
class Prog2Reference434 {
  // EXEMPEL 1: equals jamfor textens innehall.
  static boolean sameName(String left, String right) {
    return left != null && left.equalsIgnoreCase(right);
  }
  // EXEMPEL 2: String-metoder returnerar nya texter eftersom String ar immutable.
  static String cleanCode(String raw) {
    String trimmed = raw.trim();
    String upper = trimmed.toUpperCase();
    return upper.substring(0, Math.min(3, upper.length()));
  }
  // EXEMPEL 3: StringBuilder passar nar text byggs steg for steg.
  static String joinLines(java.util.List<String> lines) {
    StringBuilder builder = new StringBuilder();
    for (String line : lines) { builder.append(line).append(System.lineSeparator()); }
    return builder.toString();
  }
}
